import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

const BottomNavigation = () => {
  const { t } = useTranslation();
  const location = useLocation();

  // Icons
  const {
    HiHome,
    HiOutlineClipboardList,
    HiOutlineCalendar,
    HiOutlineUser,
    HiOutlineCog
  } = require('react-icons/hi');

  // Restored original items: Home, Medicines, Availability, Profile, Settings
  const navItems = [
    { path: '/', label: t('home'), icon: HiHome },
    { path: '/medicines', label: t('medicines'), icon: HiOutlineClipboardList },
    { path: '/availability', label: t('availability'), icon: HiOutlineCalendar },
    { path: '/profile', label: t('profile'), icon: HiOutlineUser },
    { path: '/settings', label: t('settings'), icon: HiOutlineCog }
  ];

  return (
    <nav
      className="fixed bottom-0 left-0 right-0 z-50 bg-white/95 backdrop-blur-lg border-t border-gray-200"
      style={{ 
        boxShadow: '0 -12px 24px rgba(2,6,23,0.15)',
        position: 'fixed',
        bottom: 0,
        left: 0,
        right: 0,
        zIndex: 9999
      }}
      role="navigation"
      aria-label="Bottom navigation"
    >
      <div className="absolute top-0 left-0 right-0 h-0.5" style={{ background: 'linear-gradient(90deg,#2563eb,#7c3aed,#10b981)' }} />

      <div className="flex items-center justify-around h-16 px-2 pb-[env(safe-area-inset-bottom,0px)]">
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive = location.pathname === item.path;

          return (
            <Link
              key={item.path}
              to={item.path}
              className="group relative flex-1 min-w-0 flex flex-col items-center justify-center no-underline rounded-xl transition-all"
              style={{ textDecoration: 'none' }}
              aria-label={`Navigate to ${item.label}`}
            >
              <div
                className="relative flex items-center justify-center w-10 h-10 rounded-xl transition-all duration-300"
                style={{
                  background: isActive ? 'linear-gradient(135deg,#2563eb,#7c3aed)' : 'transparent',
                  boxShadow: isActive ? '0 8px 20px rgba(37,99,235,0.35)' : 'none',
                  transform: isActive ? 'translateY(-4px) scale(1.05)' : 'none'
                }}
              >
                <Icon className={isActive ? 'text-white text-xl' : 'text-gray-600 text-xl group-hover:text-blue-600'} />
                {isActive && <div className="absolute inset-0 rounded-xl" style={{ boxShadow: 'inset 0 0 0 2px rgba(255,255,255,0.25)' }} />}
              </div>
              <span
                className="mt-1 text-[11px] leading-tight font-medium transition-colors"
                style={{ color: isActive ? '#1d4ed8' : '#4b5563' }}
              >
                {item.label}
              </span>
            </Link>
          );
        })}
      </div>
    </nav>
  );
};

export default BottomNavigation;
